// src/pages/DashboardPage.js
import React, { useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useRole } from '../context/RoleContext';
import { useToast } from '../context/ToastContext';
import FileAttachment from '../components/health-records/FileAttachment';
import { useState, useEffect } from 'react';
import healthRecordService from '../services/healthRecordService';
import appointmentService from '../services/appointmentService';
import AppointmentCalendar from '../components/appointments/AppointmentCalendar';
import PrescriptionList from '../components/prescriptions/PrescriptionList';
import SkeletonLoader from '../components/common/SkeletonLoader';
import './DashboardPage.css';

const [attachments, setAttachments] = useState({});

// Add function to fetch attachments for a record
const fetchAttachments = async (recordId) => {
    try {
        const data = await healthRecordService.getAttachments(recordId);
        setAttachments(prev => ({ ...prev, [recordId]: data }));
    } catch (error) {
        console.error('Failed to fetch attachments:', error);
    }
};

useEffect(() => {
    if (records.length > 0) {
        records.forEach(record => {
            fetchAttachments(record.id);
        });
    }
}, [records]);

const DashboardPage = () => {
    const navigate = useNavigate();
    const { user, logout } = useAuth();
    const { userRole, isRole, loading: roleLoading } = useRole();
    const { showSuccess, showError } = useToast();
    
    // Tab state
    const [activeTab, setActiveTab] = useState('records');
    
    // Health records state
    const [records, setRecords] = useState([]);
    const [recordsLoading, setRecordsLoading] = useState(true);
    const [recordsError, setRecordsError] = useState('');
    const [showAddForm, setShowAddForm] = useState(false);
    const [newRecord, setNewRecord] = useState({
        title: '',
        description: '',
        type: 'general'
    });

    // Appointments state
    const [appointmentsLoading, setAppointmentsLoading] = useState(false);
    const [appointmentsError, setAppointmentsError] = useState('');

    // Redirect master admin IMMEDIATELY - before any other logic
    useEffect(() => {
        console.log('DashboardPage - User role:', userRole);
        console.log('DashboardPage - Is master admin?', isRole('master_admin'));
        
        if (!roleLoading) {
            if (isRole('master_admin')) {
                console.log('Redirecting master admin to /admin');
                navigate('/admin', { replace: true });
                return;
            }
        }
    }, [userRole, isRole, roleLoading, navigate]);

    // ========== HEALTH RECORDS FUNCTIONS ==========
    const fetchRecords = useCallback(async () => {
        try {
            setRecordsLoading(true);
            const data = await healthRecordService.getRecords();
            setRecords(data);
        } catch (err) {
            setRecordsError('Failed to load health records');
            showError('Failed to load health records');
        } finally {
            setRecordsLoading(false);
        }
    }, [showError]);

    // ========== APPOINTMENTS FUNCTIONS ==========
    const fetchAppointments = useCallback(async () => {
        try {
            setAppointmentsLoading(true);
            await appointmentService.getAppointments();
        } catch (err) {
            setAppointmentsError('Failed to load appointments');
            showError('Failed to load appointments');
        } finally {
            setAppointmentsLoading(false);
        }
    }, [showError]);

    // Load data based on active tab - only for non-admin users
    useEffect(() => {
        if (!isRole('master_admin')) {
            if (activeTab === 'records') {
                fetchRecords();
            } else if (activeTab === 'appointments') {
                fetchAppointments();
            }
        }
    }, [activeTab, fetchRecords, fetchAppointments, isRole]);

    const handleInputChange = (e) => {
        setNewRecord({
            ...newRecord,
            [e.target.name]: e.target.value
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await healthRecordService.createRecord({
                text: newRecord.description,
                title: newRecord.title,
                type: newRecord.type,
                date: new Date().toISOString()
            });
            
            setShowAddForm(false);
            setNewRecord({ title: '', description: '', type: 'general' });
            showSuccess('Health record created successfully');
            fetchRecords();
        } catch (err) {
            showError('Failed to create record');
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this record?')) {
            try {
                await healthRecordService.deleteRecord(id);
                showSuccess('Record deleted successfully');
                fetchRecords();
            } catch (err) {
                showError('Failed to delete record');
            }
        }
    };

    // ========== UI HELPER FUNCTIONS ==========
    const getRecordTypeIcon = (type) => {
        const icons = {
            general: '📋',
            prescription: '💊',
            lab_result: '🔬',
            imaging: '🖼️',
            vaccination: '💉'
        };
        return icons[type] || '📄';
    };

    const goToProfile = () => {
        navigate('/profile');
    };

    // ========== RENDER FUNCTIONS ==========
    const renderHealthRecords = () => {
        if (recordsLoading) {
            return <SkeletonLoader type="card" count={3} />;
        }

        if (recordsError) {
            return <div className="error-message">{recordsError}</div>;
        }

        if (records.length === 0) {
            return (
                <div className="no-records">
                    <p>No health records found.</p>
                    <p>Click "Add Health Record" to create your first record.</p>
                </div>
            );
        }

        return (
            <div className="records-grid">
                {records.map((record) => (
                    <div key={record.id} className="record-card">
                        <div className="record-header">
                            <span className="record-type">
                                {getRecordTypeIcon(record.record_type || 'general')}
                            </span>
                            <button 
                                className="delete-btn"
                                onClick={() => handleDelete(record.id)}
                                title="Delete record"
                            >
                                ×
                            </button>
                                                    <FileAttachment 
                            recordId={record.id}
                            attachments={attachments[record.id] || []}
                            onAttachmentChange={() => fetchAttachments(record.id)}
                            />
                        </div>
                        <h3>{record.record_data?.title || 'Health Record'}</h3>
                        <p className="record-date">
                            {new Date(record.created_at).toLocaleDateString()}
                        </p>
                        <p className="record-description">
                            {record.record_data?.text || record.record_data || 'No description'}
                        </p>
                    </div>
                ))}
            </div>
        );
    };

    const renderAppointments = () => {
        if (appointmentsLoading) {
            return <SkeletonLoader type="card" count={2} />;
        }

        if (appointmentsError) {
            return <div className="error-message">{appointmentsError}</div>;
        }

        return <AppointmentCalendar />;
    };

    // If still loading role, show loading spinner
    if (roleLoading) {
        return <div className="loading-spinner">Loading...</div>;
    }

    // If master admin, don't render anything (will redirect)
    if (isRole('master_admin')) {
        return null;
    }

    return (
        <div className="dashboard-page">
            <div className="dashboard-header">
                <div>
                    <h1>Welcome, {user?.username}!</h1>
                    <p className="health-record-id">
                        <span className="badge">{user?.role?.replace('_', ' ').toUpperCase() || 'Patient'}</span>
                        Health Record ID: {user?.healthRecordId}
                    </p>
                </div>
                <div className="header-actions">
                    <button 
                        onClick={goToProfile} 
                        className="btn btn-secondary"
                        style={{ marginRight: '10px' }}
                    >
                        👤 Profile
                    </button>
                    <button onClick={logout} className="btn btn-secondary">
                        Logout
                    </button>
                </div>
            </div>

            {/* Tab Navigation */}
            <div className="dashboard-tabs">
                <button 
                    className={`tab ${activeTab === 'records' ? 'active' : ''}`}
                    onClick={() => setActiveTab('records')}
                >
                    📋 Health Records
                </button>
                <button 
                    className={`tab ${activeTab === 'appointments' ? 'active' : ''}`}
                    onClick={() => setActiveTab('appointments')}
                >
                    📅 Appointments
                </button>
                <button 
                    className={`tab ${activeTab === 'prescriptions' ? 'active' : ''}`}
                    onClick={() => setActiveTab('prescriptions')}
                >
                    💊 Prescriptions
                </button>
            </div>

            {/* Content based on active tab */}
            <div className="dashboard-content">
                {activeTab === 'records' && (
                    <div className="records-tab">
                        <div className="dashboard-actions">
                            <button 
                                className="btn btn-primary"
                                onClick={() => setShowAddForm(!showAddForm)}
                            >
                                {showAddForm ? 'Cancel' : '+ Add Health Record'}
                            </button>
                        </div>

                        {showAddForm && (
                            <div className="add-record-form">
                                <h3>Add New Health Record</h3>
                                <form onSubmit={handleSubmit}>
                                    <div className="form-group">
                                        <label>Record Type</label>
                                        <select 
                                            name="type" 
                                            value={newRecord.type}
                                            onChange={handleInputChange}
                                            required
                                        >
                                            <option value="general">General</option>
                                            <option value="prescription">Prescription</option>
                                            <option value="lab_result">Lab Result</option>
                                            <option value="imaging">Imaging</option>
                                            <option value="vaccination">Vaccination</option>
                                        </select>
                                    </div>

                                    <div className="form-group">
                                        <label>Title</label>
                                        <input
                                            type="text"
                                            name="title"
                                            value={newRecord.title}
                                            onChange={handleInputChange}
                                            placeholder="Enter record title"
                                            required
                                        />
                                    </div>

                                    <div className="form-group">
                                        <label>Description</label>
                                        <textarea
                                            name="description"
                                            value={newRecord.description}
                                            onChange={handleInputChange}
                                            placeholder="Enter record details"
                                            rows="4"
                                            required
                                        />
                                    </div>

                                    <button type="submit" className="btn btn-success">
                                        Save Record
                                    </button>
                                </form>
                            </div>
                        )}

                        <div className="records-section">
                            <h2>Your Health Records</h2>
                            {renderHealthRecords()}
                        </div>
                    </div>
                )}

                {activeTab === 'appointments' && (
                    <div className="appointments-tab">
                        <h2>Appointment Calendar</h2>
                        {renderAppointments()}
                    </div>
                )}

                {activeTab === 'prescriptions' && (
                    <div className="prescriptions-tab">
                        <PrescriptionList />
                    </div>
                )}
            </div>
        </div>
    );
};

export default DashboardPage;
